module top_module(
    in_1, 
    in_2, 
    sel_out, 
    CTRL
    );parameter BITWIDTH = 32;

    input [BITWIDTH-1 : 0]  in_1;
    input [BITWIDTH-1 : 0]  in_2;
    input                   CTRL;

    output [BITWIDTH-1 : 0] sel_out;

    assign sel_out = (CTRL == 1'b0) ? in_1 : in_2;

endmodule
